    if 'ju1.s4.dom' in graph_copy:
        parent_node = 'ju1.s4.dom'
    else:
        # Fallback: search for a node whose 'name' attribute matches
        for nid, attrs in graph_copy.nodes(data=True):
            if attrs.get('name') == 'ju1.s4.dom':
                parent_node = nid
                break
    if parent_node is not None:
        graph_copy.add_edge(parent_node, new_node_id, type=['RK_CONTAINS'])

    # Count EK_PACKET_SWITCH nodes that belong to ju1.s4.dom hierarchy
    count = 0
    for _, attrs in graph_copy.nodes(data=True):
        if 'EK_PACKET_SWITCH' in attrs.get('type', []):
            node_name = attrs.get('name', '')
            if node_name.startswith('ju1.s4.dom'):
